eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   FAQ_ITEMS: () => (/* binding */ FAQ_ITEMS)\n/* harmony export */ });\nconst FAQ_ITEMS = [\n    // ── Clinical / process ─────────────────────────────────────────────────────\n    {\n        id: 'no-call-required',\n        question: 'Do I need to speak with a clinician to get treatment?',\n        answer: 'No call is required. After submitting your intake, a licensed Nutree clinician reviews your health history and issues your prescription directly — unless a brief discussion is clinically necessary. You can also message your clinician 7 days a week through your patient portal.',\n        category: 'clinical',\n        pages: [\n            '/',\n            '/faq',\n            '/consult',\n            '/weight-loss',\n            '/glp-1',\n            '/nad',\n            '/sermorelin',\n            '/glutathione',\n            '/oxytocin',\n            '/b12'\n        ],\n        active: true,\n        order: 1\n    },\n    {\n        id: 'clinician-messaging',\n        question: 'Can I message my clinician directly?',\n        answer: 'Yes. Every Nutree patient has direct messaging access to their assigned clinician, 7 days a week. No waiting rooms, no phone trees — just direct access to the person managing your care.',\n        category: 'clinical',\n        pages: [\n            '/',\n            '/faq',\n            '/consult'\n        ],\n        active: true,\n        order: 2\n    },\n    {\n        id: 'prescription-at-consult',\n        question: 'Will I definitely receive a prescription?',\n        answer: 'All prescriptions are issued at the sole clinical discretion of your licensed provider, based on your health profile and clinical evaluation. Your clinician\\'s role is to determine what is medically appropriate for you.',\n        category: 'clinical',\n        pages: [\n            '/weight-loss',\n            '/glp-1',\n            '/faq'\n        ],\n        active: true,\n        order: 3\n    },\n    // ── General ────────────────────────────────────────────────────────────────\n    {\n        id: 'how-it-works',\n        question: 'How does Nutree Clinic work?',\n        answer: 'Complete a short health questionnaire, and a licensed Nutree clinician reviews your intake and issues your prescription — no call required unless clinically necessary. If prescribed, your medication is shipped free to your door from a licensed 503A pharmacy. Your clinician is available 7 days a week via direct message throughout your plan.',\n        category: 'general',\n        pages: [\n            '/',\n            '/faq'\n        ],\n        active: true,\n        order: 10\n    },\n    {\n        id: 'florida-licensed',\n        question: 'Is Nutree licensed in Florida?',\n        answer: 'Yes. Nutree Clinic LLC is a licensed Florida telehealth practice. All prescriptions are issued by Florida-licensed providers. We are LegitScript certified.',\n        category: 'general',\n        pages: [\n            '/faq'\n        ],\n        active: true,\n        order: 11\n    },\n    // ── Billing ────────────────────────────────────────────────────────────────\n    {\n        id: 'hsa-fsa',\n        question: 'Are Nutree Clinic treatments FSA/HSA eligible?',\n        answer: 'Yes. All Nutree treatment plans are self-pay and eligible for FSA and HSA reimbursement. Use your card at checkout or request a receipt for reimbursement from your plan administrator.',\n        category: 'billing',\n        pages: [\n            '/',\n            '/faq',\n            '/pricing',\n            '/weight-loss',\n            '/glp-1',\n            '/nad',\n            '/sermorelin',\n            '/glutathione',\n            '/oxytocin',\n            '/b12'\n        ],\n        active: true,\n        order: 3\n    },\n    {\n        id: 'insurance-general',\n        question: 'Do I need insurance?',\n        answer: 'No. All Nutree treatments are self-pay. All plans are FSA and HSA eligible. For Wegovy® and Mounjaro®, we can help you explore manufacturer savings programmes where applicable.',\n        category: 'billing',\n        pages: [\n            '/',\n            '/faq',\n            '/pricing'\n        ],\n        active: true,\n        order: 20\n    },\n    {\n        id: 'cancel-plan',\n        question: 'How do I cancel or adjust my plan?',\n        answer: 'You can cancel or adjust your plan anytime before your next renewal date through your patient portal. There are no cancellation fees.',\n        category: 'billing',\n        pages: [\n            '/weight-loss',\n            '/faq'\n        ],\n        active: true,\n        order: 21\n    },\n    {\n        id: 'no-hidden-fees',\n        question: 'Are there any hidden fees?',\n        answer: 'No. The price you see includes your medication, provider consultation, and free shipping. Your price remains the same throughout your treatment, at every dose level.',\n        category: 'billing',\n        pages: [\n            '/faq',\n            '/pricing'\n        ],\n        active: true,\n        order: 22\n    },\n    // ── GLP-1 ──────────────────────────────────────────────────────────────────\n    {\n        id: 'glp1-included',\n        question: 'What is included in my GLP-1 plan?',\n        answer: 'All Nutree GLP-1 plans include your medication, provider consultation, dosing supplies, and free shipping. Your price is the same at every dose level — no additional fees as your treatment progresses.',\n        category: 'glp1',\n        pages: [\n            '/weight-loss',\n            '/faq'\n        ],\n        active: true,\n        order: 30\n    },\n    {\n        id: 'glp1-sema-vs-tirz',\n        question: 'What is the difference between Compounded Semaglutide and Compounded Tirzepatide?',\n        answer: 'Semaglutide is a GLP-1 receptor agonist. Tirzepatide activates both GLP-1 and GIP receptors, producing a broader metabolic effect — clinical trials show greater average weight loss (~21% vs ~15%). Your Nutree clinician will advise which is most appropriate for your health profile.',\n        category: 'glp1',\n        pages: [\n            '/weight-loss',\n            '/faq'\n        ],\n        active: true,\n        order: 31\n    },\n    {\n        id: 'glp1-side-effects',\n        question: 'What side effects should I be aware of?',\n        answer: 'Common side effects include nausea and mild digestive discomfort, especially in the early weeks of treatment. These typically ease as dosing is titrated gradually. Your provider is available to adjust your plan throughout.',\n        category: 'glp1',\n        pages: [\n            '/weight-loss',\n            '/faq'\n        ],\n        active: true,\n        order: 32\n    },\n    {\n        id: 'brand-name-options',\n        question: 'Can I get Wegovy® or Mounjaro® through Nutree?',\n        answer: 'Yes. Nutree facilitates access to Wegovy® and Mounjaro® for eligible patients. Your clinician will advise which option is most appropriate for you based on your health profile.',\n        category: 'glp1',\n        pages: [\n            '/weight-loss',\n            '/faq'\n        ],\n        active: true,\n        order: 33\n    },\n    {\n        id: 'microdose-effectiveness',\n        question: 'Is microdosing less effective than standard dosing?',\n        answer: 'Microdosing produces more gradual results. For patients with less weight to lose or who are sensitive to side effects, it is often the more appropriate clinical choice. Your Nutree provider will advise which approach is right for your health profile.',\n        category: 'glp1',\n        pages: [\n            '/glp-1'\n        ],\n        active: true,\n        order: 34\n    },\n    {\n        id: 'microdose-switch',\n        question: 'Can I switch to a standard plan after microdosing?',\n        answer: 'Yes. Many patients complete a microdosing programme and then transition to a monthly plan. Your clinician will guide this transition based on your response and goals.',\n        category: 'glp1',\n        pages: [\n            '/glp-1'\n        ],\n        active: true,\n        order: 35\n    },\n    {\n        id: 'microdose-renewal',\n        question: 'Is there an auto-renewal?',\n        answer: 'No. Microdosing programmes are fixed-term — 5 or 10 weeks, billed upfront. There is no automatic renewal. You can choose to continue or not at the end of the programme.',\n        category: 'billing',\n        pages: [\n            '/glp-1'\n        ],\n        active: true,\n        order: 36\n    },\n    // ── NAD+ ───────────────────────────────────────────────────────────────────\n    {\n        id: 'nad-delivery-form',\n        question: 'Which NAD+ delivery form is most effective?',\n        answer: 'Injectables provide the highest bioavailability. Nasal spray offers rapid CNS absorption without needles. Patches with GHK-Cu provide continuous slow-release delivery alongside regenerative peptide benefits. Your clinician recommends the most appropriate form based on your goals and health profile.',\n        category: 'nad',\n        pages: [\n            '/nad',\n            '/faq'\n        ],\n        active: true,\n        order: 40\n    },\n    {\n        id: 'nad-ghk-cu',\n        question: 'What is GHK-Cu?',\n        answer: 'GHK-Cu (copper tripeptide-1) is a naturally occurring peptide that declines with age, studied for its role in collagen synthesis, tissue repair, and anti-inflammatory activity. Combined with transdermal NAD+, it offers complementary cellular support.',\n        category: 'nad',\n        pages: [\n            '/nad'\n        ],\n        active: true,\n        order: 41\n    },\n    {\n        id: 'nad-results-timeline',\n        question: 'How long before I notice results from NAD+?',\n        answer: 'Most patients notice initial changes in energy and mental clarity within 2–4 weeks. Deeper cellular and longevity benefits build over 8–12 weeks of consistent use.',\n        category: 'nad',\n        pages: [\n            '/nad'\n        ],\n        active: true,\n        order: 42\n    },\n    // ── Sermorelin ─────────────────────────────────────────────────────────────\n    {\n        id: 'ser-vs-hgh',\n        question: 'How does Sermorelin differ from synthetic growth hormone?',\n        answer: \"Synthetic HGH replaces your growth hormone directly, bypassing your body's natural regulation. Sermorelin instead signals the gland in your brain that controls growth hormone production to release more of your own — keeping your body's natural feedback loops intact. This is why many providers prefer it as a more physiologic approach to growth hormone support.\",\n        category: 'sermorelin',\n        pages: [\n            '/sermorelin',\n            '/faq'\n        ],\n        active: true,\n        order: 50\n    },\n    {\n        id: 'ser-administration',\n        question: 'How is Sermorelin administered?',\n        answer: 'A small subcutaneous injection self-administered at home — typically into the abdomen, on an empty stomach before bedtime, five nights per week. Your provider guides you through the technique at your first review.',\n        category: 'sermorelin',\n        pages: [\n            '/sermorelin'\n        ],\n        active: true,\n        order: 51\n    },\n    {\n        id: 'ser-fda',\n        question: 'Is Sermorelin FDA-approved?',\n        answer: 'Sermorelin was previously FDA-approved but the manufacturer discontinued it in 2006 for commercial reasons, not safety concerns. It remains available as a compounded medication from licensed 503A pharmacies. All prescriptions are issued at the sole clinical discretion of your licensed Nutree provider.',\n        category: 'sermorelin',\n        pages: [\n            '/sermorelin',\n            '/faq'\n        ],\n        active: true,\n        order: 52\n    },\n    {\n        id: 'ser-duration',\n        question: 'How long should I take Sermorelin?',\n        answer: 'Most providers recommend 3–6 months for full results. The 10-week starter plan is a structured way to experience the initial effects. Your clinician will guide your plan based on your response and goals.',\n        category: 'sermorelin',\n        pages: [\n            '/sermorelin'\n        ],\n        active: true,\n        order: 53\n    },\n    {\n        id: 'ser-results',\n        question: 'How long before I see results from Sermorelin?',\n        answer: 'Most patients notice improved sleep within the first 2 weeks. Energy and recovery improvements typically follow in weeks 3–6. Visible body composition changes develop over months 2–3 of consistent use. Individual results vary.',\n        category: 'sermorelin',\n        pages: [\n            '/sermorelin',\n            '/faq'\n        ],\n        active: true,\n        order: 54\n    },\n    // ── Glutathione ────────────────────────────────────────────────────────────\n    {\n        id: 'glut-fda',\n        question: 'Is glutathione FDA-approved?',\n        answer: 'Compounded glutathione is not FDA-approved. It is prepared by licensed 503A compounding pharmacies and prescribed off-label. All prescriptions are issued at the sole clinical discretion of your licensed Nutree provider.',\n        category: 'glutathione',\n        pages: [\n            '/glutathione',\n            '/faq'\n        ],\n        active: true,\n        order: 60\n    },\n    {\n        id: 'glut-administration',\n        question: 'How is glutathione administered?',\n        answer: 'As a subcutaneous injection self-administered at home. Your clinician determines the appropriate frequency based on your goals and health profile.',\n        category: 'glutathione',\n        pages: [\n            '/glutathione'\n        ],\n        active: true,\n        order: 61\n    },\n    {\n        id: 'glut-glp1-synergy',\n        question: 'How does glutathione complement GLP-1 therapy?',\n        answer: 'Patients with high oxidative stress sometimes experience a blunted response to GLP-1 medications. Glutathione helps restore the cellular environment that allows metabolic treatments to work more effectively.',\n        category: 'glutathione',\n        pages: [\n            '/glutathione'\n        ],\n        active: true,\n        order: 62\n    },\n    // ── Oxytocin ───────────────────────────────────────────────────────────────\n    {\n        id: 'oxy-vs-obstetric',\n        question: 'Is this the same oxytocin used in obstetrics?',\n        answer: 'The same molecule, at a very different dose and delivery method. Obstetric use involves intravenous administration at high doses for uterine effects. Nasal spray therapy uses much smaller doses targeting CNS receptors for mood and stress regulation. The applications are entirely different.',\n        category: 'oxytocin',\n        pages: [\n            '/oxytocin'\n        ],\n        active: true,\n        order: 70\n    },\n    {\n        id: 'oxy-anxiety',\n        question: 'Is this a treatment for anxiety or depression?',\n        answer: \"Oxytocin therapy at Nutree is a wellness treatment for stress relief and emotional well-being. It is not a psychiatric treatment and is not a substitute for therapy or psychiatric medication. If you are experiencing a clinical condition, your provider will advise accordingly.\",\n        category: 'oxytocin',\n        pages: [\n            '/oxytocin'\n        ],\n        active: true,\n        order: 71\n    },\n    // ── B12 ────────────────────────────────────────────────────────────────────\n    {\n        id: 'b12-difference',\n        question: 'What is the difference between B6 and B12?',\n        answer: 'B12 (cobalamin) is involved in red blood cell formation, energy metabolism, and neurological function. B6 (pyridoxine) plays a key role in neurotransmitter synthesis and immune function. They work synergistically — particularly in mood regulation and metabolic health — which is why they are often prescribed together.',\n        category: 'b12',\n        pages: [\n            '/b12'\n        ],\n        active: true,\n        order: 80\n    },\n    {\n        id: 'b12-results',\n        question: 'How quickly will I notice results from B12?',\n        answer: 'Injectable B12 often produces noticeable energy improvements within days. Oral supplementation typically takes 2–4 weeks. Full restoration of depleted levels generally takes 4–8 weeks of consistent use.',\n        category: 'b12',\n        pages: [\n            '/b12'\n        ],\n        active: true,\n        order: 81\n    },\n    {\n        id: 'b12-injectable-appropriate',\n        question: 'Is the injectable form appropriate for me?',\n        answer: 'Your Nutree clinician will recommend the most appropriate form based on your health history, goals, and any factors that may affect absorption.',\n        category: 'b12',\n        pages: [\n            '/b12'\n        ],\n        active: true,\n        order: 82\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(rsc)/./src/lib/faq.config.ts\n");

